`,l.jsx(r.h2,{children:"WordPress and CMS platforms: different layer, different strength"}),`
`,l.jsxs(r.p,{children:[l.jsx(r.a,{href:"https://wordpress.org/",target:"_blank",rel:"noopener noreferrer",children:"WordPress"})," powers a large percentage of the public web — particularly for blogs, marketing sites, and small commerce. Themes, plugins, editorial workflows, and SEO tooling remain difficult to match for time-to-value in pure publishing scenarios."]}),`
`,l.jsxs(r.p,{children:["Tension appears when the ",l.jsx(r.strong,{children:"product is primarily an interactive application"}),": personalised dashboards, complex client validation, real-time data, and bespoke workflows. Teams then often separate ",l.jsx(r.strong,{children:"content"})," from ",l.jsx(r.strong,{children:"experience"})," — for example, headless WordPress (or another CMS) for editorial data, with React or another framework for the front end. WordPress has also embraced block editing and modern JavaScript in its own ecosystem."]}),`
`,l.jsxs(r.p,{children:["React did not make WordPress obsolete. The two frequently ",l.jsx(r.strong,{children:"coexist"}),": WordPress for content operations, React for rich client surfaces where that split makes sense."]}),`
